#include <stdio.h>
int main()
{

    int i=0,n,k,countG=0,countT=0,locationG,locationT,pathDistance;
    char s[100];
    scanf("%d %d",&n,&k);
    if((n >= 2 && n <= 100) && (k >= 1 && k <= (n-1)))
    {
        while(i <= n)
        {
            scanf("%c",&s[i]);
            i++;
        }
        for(i = 1; i <= n; i++)
        {
            if(s[i] == '.' || s[i] == '#' || s[i] == 'G' || s[i] == 'T')
            {
                continue;

            }
            else
            {

                return 0;

            }
        }
        for(i = 1; i <= n; i++)
        {
            if(s[i] == 'G')
            {
                countG++;
            }
            if(s[i] == 'T')
            {
                countT++;
            }

        }
        if(countG != 1 || countT != 1)
        {
            return 0;
        }
        for(i = 1; i <= n; i++)
        {
            if(s[i] == 'G')
            {
                locationG = i;
            }
            if(s[i] == 'T')
            {
                locationT = i;
            }
        }

        pathDistance = locationG - locationT;
        if(pathDistance > 0)
        {
            if(pathDistance < k)
            {
                printf("NO");
                return 0;
            }
            else
            {
                for(i = k; i <= n; i += k)
                {
                    if(s[locationG-i] == '#')
                    {
                        printf("NO");
                        return 0;
                    }
                    else if(s[locationG-i] == 'T')
                    {
                        printf("YES");
                        return 0;
                    }
                    else if(locationG-i < locationT )
                    {
                        printf("NO");
                        return 0;
                    }
                    else
                    {
                        continue;
                    }
                }
            }
        }
        else
        {
            if(-pathDistance < k)
            {
                printf("NO");
                return 0;
            }
            else
            {
                for(i = k; i <= n; i += k)
                {
                    if(s[locationG+i] == '#')
                    {
                        printf("NO");
                        return 0;
                    }
                    else if(s[locationG+i] == 'T')
                    {
                        printf("YES");
                        return 0;
                    }
                    else if(locationG+i > locationT)
                    {
                        printf("NO");
                        return 0;
                    }
                    else
                    {
                        continue;
                    }
                }
            }

        }

    }

    return 0;
}

