use std::io::prelude::*;
use std::io;
use std::str::FromStr;
#[cfg(local)]
use std::fs::File;
#[cfg(local)]
use std::io::BufReader;

#[cfg(local)]
fn buf_read() -> io::Result<(Vec<String>)> {
    let f = try!(File::open("input.txt"));
    let input_lines: Vec<_> = BufReader::new(f).lines().collect();
    let lines: Vec<String> = input_lines.into_iter().map(|e| e.unwrap()).collect();
    Ok((lines))
}

#[cfg(not(local))]
fn buf_read() -> io::Result<(Vec<String>)> {
    let stdin = io::stdin();
    let input_lines: Vec<_> = stdin.lock().lines().collect();
    let lines: Vec<String> = input_lines.into_iter().map(|e| e.unwrap()).collect();
    Ok((lines))
}

fn main() {
    type Element = String;
    let input = buf_read().unwrap();
    let mut input_vectors: Vec<Vec<Element>> = vec![];
    for input_line in input {
        let input_str: Vec<String> = input_line.split(' ').map(String::from).collect();
        let mut input_vector: Vec<Element> = vec![];
        for input_elem_str in input_str {
            let elem: Element = Element::from_str(input_elem_str.as_str()).unwrap();
            input_vector.push(elem);
        }
        input_vectors.push(input_vector);
    }
    let mut k = i64::from_str(&input_vectors[0][1]).unwrap();
    let mut i = 0;
    let mut str = input_vectors[1][0].char_indices();
    // let mut str2 = str.clone();
    // let mut str3 = str.clone();
    // let g_position = str2.position(|(u, c)| c == 'G').unwrap() as i64;
    // let t_position = str3.position(|(u, c)| c == 'T').unwrap() as i64;
    let mut start_flag = 0;
    let mut result_flag = 0;

    for c in str {
        if start_flag == 1 {
            i += 1;
            if i % k != 0 {
                continue;
            }
        }
        // println!("{:?}", c);
        match c {
            (n, c) => {
                if c == '#' {
                    // println!("{:?}", c);
                    if start_flag == 1 {
                        break;
                    }
                } else if c == 'G' || c == 'T' {
                    // println!("{:?}", c);
                    // println!("{:?}", start_flag);

                    if start_flag == 0 {
                        start_flag = 1;
                    } else {
                        result_flag = 1;
                        break;
                    }
                }
            }
        }
        // println!{"{:?}", c};
    }
    if result_flag == 0 {
        println!("No");
    } else {
        println!("Yes");
    }
}
